import React, { useEffect, useState } from 'react'
import { Img_URL, fetchMovie } from '../../utils/fetchApi';
import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';

const TopRated = () => {
  const [page,setPage]=useState(1);
  const [TopRatedMovieList,setTopRatedMovieList]=useState([])

  const loadMoreHandle=()=>{
   setPage((prev)=> prev + 1);
   refetch();
   setTopRatedMovieList((prev)=> [...prev,...Toprated]);
   console.log(TopRatedMovieList);
 }

  const { isLoading,isError,error ,data: Toprated,refetch} = useQuery({
      queryKey: ["Movie", "Toprated"],
      keepPreviousData: true,
      staleTime:60000,
      queryFn: () =>
        fetchMovie("toprated",`${page}`).then((res) => {
          setTopRatedMovieList(res.results)
          return res.results;
        }),
    });



    useEffect(()=>{
      // refetch();
      return()=>{
        refetch();
      }
    },[refetch,page]);

    if (isLoading) {
      return (
        <div className="loading">
          <h1>Loading...</h1>
        </div>
      );
    } else if (isError) {
      return (
        <div className="error">
          <p>{error.message}</p>
        </div>
      );
    } else
return (
  <div className="Popular">
        <h1>Popular Movies</h1>
        <div>
        {TopRatedMovieList?.map((item) => (
            <Link to={`/movie/${item.id}`} className="card" key={item.title}>
              <img src={`${Img_URL}${item.poster_path}`} alt="img" />
            </Link>
        ))}
        </div>
        <button onClick={loadMoreHandle}>More</button>
      </div>
)
}

export default TopRated
